import { callMcpSkill } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const result = await callMcpSkill({
    toolId,
    toolName: "search_and_get_outcomes",
    args: {
      query: "Super Bowl 2026 winner",
      category: "sports"
    }
  });

  const outcomes = Array.isArray(result?.outcomes) ? result.outcomes : [];

  const semanticRanked = pickTopSemanticCandidates({
    target: "Super Bowl 2026 winner outcomes",
    candidates: outcomes,
    requiredTerms: ["Super Bowl", "winner"],
    avoidTerms: ["MVP", "prop", "spread", "total"],
    limit: 3
  });

  const top3 = (Array.isArray(semanticRanked) && semanticRanked.length > 0
    ? semanticRanked
    : outcomes
        .filter((o) => o && typeof o.price === "number")
        .sort((a, b) => b.price - a.price)
  )
    .slice(0, 3)
    .map((o, index) => ({
      rank: index + 1,
      name: o.name,
      currentYESPrice: o.price
    }));

  return {
    eventTitle: result?.eventTitle ?? null,
    eventSlug: result?.eventSlug ?? null,
    searchMethod: result?.searchMethod ?? null,
    matchConfidence: result?.matchConfidence ?? null,
    top3OutcomesByImpliedPrice: top3,
    crossVenueComparisonAvailable: false,
    note: "Cross-venue comparison is unavailable because no other marketplace tool was used; this ranks Polymarket outcomes only with live numbers.",
    fetchedAt: result?.fetchedAt ?? null
  };
}

