    toolId,
    toolName: "browse_category",
    args: {
      category: "sports",
      limit: 30,
      sortBy: "volume",
    },
  });

  const events = Array.isArray(browse?.events) ? browse.events : [];

  const grouped = new Map();

  for (const event of events) {
    const title = event && typeof event.title === "string" ? event.title : "";
    const slug = event && typeof event.slug === "string" ? event.slug : "";
    const conditionId = event && typeof event.conditionId === "string" ? event.conditionId : "";
    const volume = event && typeof event.volume === "number" ? event.volume : null;
    const url = event && typeof event.url === "string" ? event.url : "";

    const championshipKey = (() => {
      const t = title.toLowerCase();
      if (t.includes("championship")) return "championship";
      if (t.includes("winner")) return "winner";
      if (t.includes("mvp")) return "mvp";
      if (t.includes("finals")) return "finals";
      if (t.includes("open")) return "open";
      return null;
    })();

    if (!championshipKey) continue;

    const buckets = grouped.get(championshipKey) || [];
    buckets.push({ title, slug, conditionId, volume, url });
    grouped.set(championshipKey, buckets);
  }

  let chosenGroup = null;
  let chosenPair = null;

  for (const [, items] of grouped.entries()) {
    if (items.length >= 2) {
      const sorted = [...items].sort((a, b) => (b.volume ?? -1) - (a.volume ?? -1));
      chosenGroup = sorted;
      chosenPair = [sorted[0], sorted[1]];
      break;
    }
  }

  if (!chosenPair) {
    return {
      browseCategory: browse,
      selectedPair: null,
      correlation: null,
      note: "No clear pair of sports markets referencing the same championship was found in the top 30 results.",
    };
  }

  const larger = chosenPair[0];
  const smaller = chosenPair[1];

  const correlated = await callMcpSkill({
    toolId,
    toolName: "find_correlated_markets",
    args: larger.conditionId ? { conditionId: larger.conditionId } : { slug: larger.slug },
  });

  const top3 = Array.isArray(correlated?.correlatedMarkets)
    ? correlated.correlatedMarkets
        .slice()
        .sort((a, b) => (b.correlationScore ?? -1) - (a.correlationScore ?? -1))
        .slice(0, 3)
        .map((m) => ({
          title: m.title,
          conditionId: m.conditionId,
          currentPrice: m.currentPrice,
          correlationType: m.correlationType,
          correlationScore: m.correlationScore,
          hedgeNote: m.hedgeNote,
        }))
    : [];

  return {
    selectedPair: {
      largerMarket: larger,
      smallerMarket: smaller,
    },
    correlatedMarketsTop3: top3,
    source: {
      browseCategory: {
        category: "sports",
        limit: 30,
        sortBy: "volume",
      },
      note: "Data is from a past query in this chat turn.",
    },
    correlationSourceMarket: correlated?.sourceMarket ?? null,
  };
}

import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const browse = await callMcpSkill({
    toolId,
    toolName: "browse_category",
    args: {
      category: "sports",
      limit: 30,
      sortBy: "volume",
    },
  });

  const events = Array.isArray(browse?.events) ? browse.events : [];

  const normalize = (s) =>
    String(s || "")
      .toLowerCase()
      .replace(/\s+/g, " ")
      .replace(/\s*winner\s*$/i, "")
      .replace(/\s*champion\s*$/i, "")
      .replace(/\s*championship\s*$/i, "")
      .replace(/\s*finals\s*$/i, "")
      .trim();

  const thematicRoot = (title) => {
    const t = normalize(title);
    if (t.includes("world cup")) return "world cup";
    if (t.includes("premier league")) return "premier league";
    if (t.includes("champions league")) return "champions league";
    if (t.includes("la liga")) return "la liga";
    if (t.includes("bundesliga")) return "bundesliga";
    if (t.includes("serie a")) return "serie a";
    if (t.includes("ligue 1")) return "ligue 1";
    if (t.includes("stanley cup")) return "stanley cup";
    if (t.includes("world series")) return "world series";
    if (t.includes("wimbledon")) return "wimbledon";
    if (t.includes("australian open")) return "australian open";
    if (t.includes("ncaa tournament")) return "ncaa tournament";
    if (t.includes("f1")) return "f1";
    if (t.includes("mvp")) return "mvp";
    return null;
  };

  const grouped = new Map();

  for (const event of events) {
    const title = event && typeof event.title === "string" ? event.title : "";
    const slug = event && typeof event.slug === "string" ? event.slug : "";
    const conditionId = event && typeof event.conditionId === "string" ? event.conditionId : "";
    const volume = event && typeof event.volume === "number" ? event.volume : null;
    const url = event && typeof event.url === "string" ? event.url : "";
    const key = thematicRoot(title);
    if (!key) continue;
    const buckets = grouped.get(key) || [];
    buckets.push({ title, slug, conditionId, volume, url });
    grouped.set(key, buckets);
  }

  let chosenPair = null;

  for (const [, items] of grouped.entries()) {
    if (items.length >= 2) {
      const sorted = [...items].sort((a, b) => (b.volume ?? -1) - (a.volume ?? -1));
      if (normalize(sorted[0].title) !== normalize(sorted[1].title)) {
        chosenPair = [sorted[0], sorted[1]];
        break;
      }
    }
  }

  if (!chosenPair) {
    return {
      browseCategory: browse,
      selectedPair: null,
      correlation: null,
      note: "No clear pair of sports markets referencing the same championship was found in the top 30 results.",
    };
  }

  const larger = chosenPair[0];
  const smaller = chosenPair[1];

  const correlated = await callMcpSkill({
    toolId,
    toolName: "find_correlated_markets",
    args: larger.conditionId ? { conditionId: larger.conditionId } : { slug: larger.slug },
  });

  const largerRoot = thematicRoot(larger.title);
  const top3 = Array.isArray(correlated?.correlatedMarkets)
    ? correlated.correlatedMarkets
        .filter((m) => {
          const root = thematicRoot(m && m.title);
          return root && root === largerRoot;
        })
        .slice()
        .sort((a, b) => (b.correlationScore ?? -1) - (a.correlationScore ?? -1))
        .slice(0, 3)
        .map((m) => ({
          title: m.title,
          conditionId: m.conditionId,
          currentPrice: m.currentPrice,
          correlationType: m.correlationType,
          correlationScore: m.correlationScore,
          hedgeNote: m.hedgeNote,
        }))
    : [];

  return {
    selectedPair: {
      largerMarket: larger,
      smallerMarket: smaller,
    },
    correlatedMarketsTop3: top3,
    source: {
      browseCategory: {
        category: "sports",
        limit: 30,
        sortBy: "volume",
      },
      note: top3.length
        ? "The correlated markets were filtered to the same championship theme as the selected market."
        : "No thematic matches for the selected championship were found in the top 30 sports markets; unrelated defaults were excluded.",
    },
    correlationSourceMarket: correlated?.sourceMarket ?? null,
  };
}

