import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

const POLYMARKET_TOOL_ID = "294100e8-c648-4e5f-a254-95a14b56e398";

function normalizeMarkets(results) {
  return Array.isArray(results) ? results.filter(Boolean) : [];
}

function extractConditionIds(markets) {
  return normalizeMarkets(markets)
    .map((m) => (m && m.conditionId ? String(m.conditionId) : ""))
    .filter((x) => x.length > 0);
}

function buildOiMap(openInterestRows) {
  const rows = Array.isArray(openInterestRows) ? openInterestRows : [];
  const map = {};
  for (const row of rows) {
    if (!row || !row.conditionId) continue;
    map[String(row.conditionId)] = row.value;
  }
  return map;
}

function scoreByOpenInterest(markets, oiMap) {
  return normalizeMarkets(markets).map((m) => ({
    ...m,
    openInterest: m && m.conditionId && typeof oiMap[String(m.conditionId)] === "number"
      ? oiMap[String(m.conditionId)]
      : null,
  }));
}

function chooseBestCandidate(candidates) {
  const rows = normalizeMarkets(candidates).slice();
  rows.sort((a, b) => {
    const boi = typeof b.openInterest === "number" ? b.openInterest : -1;
    const aoi = typeof a.openInterest === "number" ? a.openInterest : -1;
    if (boi !== aoi) return boi - aoi;
    const bliq = typeof b.liquidity === "number" ? b.liquidity : -1;
    const aliq = typeof a.liquidity === "number" ? a.liquidity : -1;
    if (bliq !== aliq) return bliq - aliq;
    return String(a.title || "").localeCompare(String(b.title || ""));
  });
  return rows[0] || null;
}

function pickSemanticMacroCandidates(markets) {
  return pickTopSemanticCandidates({
    target: "live macro market on Polymarket",
    candidates: normalizeMarkets(markets),
    requiredTerms: ["macro"],
    avoidTerms: ["sports", "team", "player", "candidate", "election", "award"],
    limit: 20,
  });
}

